import { signUpEmailOptions, useAuth } from "@better-auth-ui/solid"
import { createMutation } from "@tanstack/solid-query"
import { createSignal, Show } from "solid-js"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"

export type SignUpProps = {
  callbackURL?: string
}

export function SignUp(props: SignUpProps) {
  const auth = useAuth()
  const [email, setEmail] = createSignal("")
  const [name, setName] = createSignal("")
  const [password, setPassword] = createSignal("")
  const signUp = createMutation(() => signUpEmailOptions(auth.authClient))

  const submitSignUp = (event: SubmitEvent) => {
    event.preventDefault()

    signUp.mutate({
      callbackURL: props.callbackURL,
      email: email(),
      name: name(),
      password: password()
    })
  }

  return (
    <form aria-label="Sign up" onSubmit={submitSignUp}>
      <h1>Sign up</h1>
      <p>Create an account with email and password.</p>
      <Show when={auth.emailAndPassword.name}>
        <Label for="sign-up-name">Name</Label>
        <Input
          autocomplete="name"
          id="sign-up-name"
          name="name"
          onInput={(event) => setName(event.currentTarget.value)}
          required={auth.emailAndPassword.name}
          type="text"
          value={name()}
        />
      </Show>
      <Label for="sign-up-email">Email</Label>
      <Input
        autocomplete="email"
        id="sign-up-email"
        name="email"
        onInput={(event) => setEmail(event.currentTarget.value)}
        required
        type="email"
        value={email()}
      />
      <Label for="sign-up-password">Password</Label>
      <Input
        autocomplete="new-password"
        id="sign-up-password"
        maxLength={auth.emailAndPassword.maxPasswordLength}
        minLength={auth.emailAndPassword.minPasswordLength}
        name="password"
        onInput={(event) => setPassword(event.currentTarget.value)}
        required
        type="password"
        value={password()}
      />
      <Button disabled={signUp.isPending} type="submit">
        {signUp.isPending ? "Creating account…" : "Create account"}
      </Button>
      <Show when={signUp.isSuccess}>
        <p role="status">
          Account created. Check your email if verification is required.
        </p>
      </Show>
      <Show when={signUp.isError}>
        <p role="alert">Unable to create an account. Try again.</p>
      </Show>
    </form>
  )
}

import { type ButtonRootProps, Root } from "@kobalte/core/button"
import type { PolymorphicProps } from "@kobalte/core/polymorphic"
import { cva, type VariantProps } from "class-variance-authority"
import { type ComponentProps, splitProps, type ValidComponent } from "solid-js"
import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "group/button z-button inline-flex shrink-0 select-none items-center justify-center whitespace-nowrap outline-none transition-all active:not-aria-[haspopup]:translate-y-px disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "z-button-variant-default",
        outline: "z-button-variant-outline",
        secondary: "z-button-variant-secondary",
        ghost: "z-button-variant-ghost",
        destructive: "z-button-variant-destructive",
        link: "z-button-variant-link"
      },
      size: {
        default: "z-button-size-default",
        xs: "z-button-size-xs",
        sm: "z-button-size-sm",
        lg: "z-button-size-lg",
        icon: "z-button-size-icon",
        "icon-xs": "z-button-size-icon-xs",
        "icon-sm": "z-button-size-icon-sm",
        "icon-lg": "z-button-size-icon-lg"
      }
    },
    defaultVariants: {
      variant: "default",
      size: "default"
    }
  }
)

type ButtonProps<T extends ValidComponent = "button"> = PolymorphicProps<
  T,
  ButtonRootProps<T>
> &
  VariantProps<typeof buttonVariants> &
  Pick<ComponentProps<T>, "class">

const Button = <T extends ValidComponent = "button">(props: ButtonProps<T>) => {
  const [local, others] = splitProps(props as ButtonProps, [
    "variant",
    "size",
    "class"
  ])

  return (
    <Root
      class={cn(
        buttonVariants({ variant: local.variant, size: local.size }),
        local.class
      )}
      data-slot="button"
      {...others}
    />
  )
}

export { Button, type ButtonProps, buttonVariants }

import { type ComponentProps, splitProps } from "solid-js"
import { cn } from "@/lib/utils"

type InputProps = ComponentProps<"input">

const Input = (props: InputProps) => {
  const [local, others] = splitProps(props, ["class"])

  return (
    <input
      class={cn(
        "z-input w-full min-w-0 outline-none file:inline-flex file:border-0 file:bg-transparent file:text-foreground placeholder:text-muted-foreground disabled:pointer-events-none disabled:cursor-not-allowed disabled:opacity-50",
        local.class
      )}
      data-slot="input"
      {...others}
    />
  )
}

export { Input, type InputProps }

/** biome-ignore-all lint/a11y/noLabelWithoutControl: component file; for/htmlFor is provided by consumers */
import type { ComponentProps } from "solid-js"
import { splitProps } from "solid-js"
import { cn } from "@/lib/utils"

type LabelProps = ComponentProps<"label">

const Label = (props: LabelProps) => {
  const [local, others] = splitProps(props, ["class"])

  return (
    <label
      class={cn(
        "z-label flex select-none items-center peer-disabled:cursor-not-allowed group-data-[disabled=true]:pointer-events-none",
        local.class
      )}
      data-slot="label"
      {...others}
    />
  )
}

export { Label, type LabelProps }

import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

export const cn = (...inputs: ClassValue[]) => twMerge(clsx(inputs))
